import React, { Fragment, useState, useEffect } from "react";
import {
  BrowserRouter as Router,
  Route,
  Routes,
  Navigate,
} from "react-router-dom";

import Home_Customer from "./routes/Home_Customer";
import Home from "./routes/Home";
import Login from "./routes/Login";
import Registration from "./routes/Registration";
import ProductDetails from "./routes/ProductDetails"; 

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true); // State to track loading state
  const setAuth = (boolean) => {
    setIsAuthenticated(boolean);
  };

  useEffect(() => {
    // Call the middleware endpoint to check user type
    const checkUserType = async () => {
      try {
        const response = await fetch("/api/checkUserType", {
          method: "GET",
          headers: {
            "Content-Type": "application/json",
            "jwtToken": localStorage.token // Assuming the token is stored in localStorage
          }
        });
        const data = await response.json();

        // If user type is customer, set authenticated to true
        if (data.userType === 2) {
          setIsAuthenticated(true);
        }

        setLoading(false); // Set loading to false after checking user type
      } catch (error) {
        console.error("Error:", error);
        setLoading(false); // Set loading to false if there's an error
      }
    };

    checkUserType(); // Call the function when component mounts
  }, []);

  if (loading) {
    return <div>Loading...</div>; // Render loading state while checking user type
  }

  return (
    <Fragment>
      <Router>
        <Routes>
          <Route path="/" 
          element={
            isAuthenticated ? <Home_Customer /> : <Home />
          }
          />
          <Route
            path="/login"
            element={
              !isAuthenticated ? (
                <Login setAuth={setAuth} />
              ) : (
                <Navigate to="/" />
              )
            }
          />
          <Route
            path="/registration"
            element={
              !isAuthenticated ? (
                <Registration setAuth={setAuth} />
              ) : (
                <Navigate to="/" />
              )
            }
          />
          <Route path="/product/:id" element={<ProductDetails />} />{" "}
        </Routes>
      </Router>
    </Fragment>
  );
};

export default App;
